mapper.select:
SELECT p.*,
	(SELECT COUNT(*) FROM pa_mst_block b WHERE b.parent_id = p.id AND b.active_status = 'Y') total_blocks,
	(SELECT COUNT(*) FROM pa_mst_floor f JOIN pa_mst_block b ON b.id = f.parent_id WHERE b.parent_id = p.id AND f.active_status = 'Y') total_floors,
	(SELECT COUNT(*) FROM pa_mst_unit u JOIN pa_mst_floor f ON f.id = u.parent_id JOIN pa_mst_block b ON b.id = f.parent_id WHERE b.parent_id = p.id AND u.active_status = 'Y') total_units,
	(SELECT COUNT(*) FROM pa_mst_amenity a WHERE a.parent_id = p.id AND a.active_status = 'Y') total_amenities
FROM pa_mst_property p

	AND p.company_id = #{companyId}
	AND p.active_status = 'Y'

		AND (LOWER(p.code) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.city) LIKE CONCAT('%', LOWER(#{search}), '%'))

	AND p.region = #{region}
	AND p.property_type = #{propertyType}
	AND p.onboarding_status = #{onboardingStatus}

ORDER BY p.updated_on DESC, p.name
LIMIT #{pageSize} OFFSET #{offset}
